from docx import Document
from docx.shared import Pt, Inches
from docx.enum.text import WD_ALIGN_PARAGRAPH, WD_LINE_SPACING

def create_lake_star_student():
    doc = Document()
    for section in doc.sections:
        section.top_margin, section.bottom_margin = Inches(1), Inches(1)
        section.left_margin, section.right_margin = Inches(1), Inches(1)

    style = doc.styles['Normal']
    style.font.name = 'Arial'
    style.font.size = Pt(14)
    style.paragraph_format.line_spacing_rule = WD_LINE_SPACING.ONE_POINT_FIVE

    doc.add_heading('ДЕЛ 1: НАСОКИ ЗА УЧЕНИКОТ', 1)
    doc.add_paragraph("Во овој тест ќе прочиташ еден расказ и ќе одговориш на неколку прашања за она што си го прочитал/а. Некои прашања можеби ќе ти бидат лесни, а некои потешки. За некои прашања ќе треба да го избереш најдобриот одговор со заокружување на буквата перед него (А, Б, В или Г). За други прашања ќе треба да го напишеш твојот одговор на празните линии. До прашањата каде што треба да пишуваш има нацртано моливче со број (1 или 2), што покажува колку поени носи твоето објаснување. Дади сè од себе да ги одговориш сите прашања.")
    
    doc.add_page_break()
    doc.add_heading('Спасувањето на „Езерската ѕвезда“', 0).alignment = WD_ALIGN_PARAGRAPH.CENTER

    paragraphs = [
        "Десетгодишниот Тео го обожаваше езерото. Секое лето го поминуваше кај својот дедо Никола во малата куќа покрај брегот. Најмногу од сѐ, Тео сакаше да ги гледа големите бели едрилици како се лизгаат по водата. Еден ден, додека истражуваше низ густата трска во плитакот, Тео забележа нешто чудно. Под еден стар, изгниен трупец ѕиркаше парче дрво обоено во избледена сина боја.",
        "Тео внимателно го извлече предметот. Тоа беше стара, скршена макета на едрилица. Едрото ѝ беше скинато, дрвото беше изгребано, а на нејзиниот труп едвај се читаа избледените букви: „Езерска ѕвезда“. Тео веднаш почувствува силна поврзаност со малото бродче. Срцето му заигра од возбуда, бидејќи отсекогаш сонуваше да има своја едрилица, дури и ако е само макета.",
        "[ 🎨 NanoBanana Prompt: A 10-year-old boy named Teo finding an old, broken, faded blue wooden toy sailboat hidden in the thick green reeds by a calm lake. In the style of a clean children's picture book, pastel colors, white background bleed --ar 16:9 ]",
        "Тој потрча кон дворот каде што дедо Никола поправаше една стара рибарска мрежа.\n„Дедо, погледни што најдов! Дали можеме да ја поправиме?“ – праша Тео со надеж во гласот.\nДедо Никола ги стави очилата, го зеде бродчето во своите груби раце и благо се насмевна. „Ова е многу старо бродче, Тео. Ќе ни треба многу трпение, шмиргла за дрво и нова сина боја. Но, ако си подготвен да работиш напорно, ’Езерската ѕвезда‘ повторно ќе заплови.“",
        "Следните две недели, Тео и дедо му работеа секој ден. Тео внимателно го мазнеше дрвото со шмирглата додека не стана мазно како стакло. Потоа го бојадисаа со светла, блескаво сина боја, а дедо Никола соши прекрасно ново бело едро од едно старо платно. Бродчето изгледаше како ново, подготвено да ги освои езерските бранови.",
        "[ 🎨 NanoBanana Prompt: A young boy and his kind grandfather with glasses working together happily in a yard to sand and paint an old wooden toy boat bright blue. The grandfather is holding a new white sail. In the style of a clean children's picture book, pastel colors, white background bleed --ar 16:9 ]",
        "Конечно дојде денот за првата пловидба. Тео гордо ја носеше „Езерската ѕвезда“ кон главното пристаниште каде што се собираа децата од селото. Таму беше и Бојан, момче кое секогаш ги имаше најскапите играчки. Во рацете држеше огромна, сјајна пластична едрилица на далечинско управување.",
        "„Што е тоа, Тео?“ – праша Бојан и гласно се насмеа. „Изгледа како парче старо дрво што си го нашол во ѓубрето. Погледни ја мојата едрилица, таа е најбрзата на целото езеро!“\nТео ги наведе очите и цврсто го гушна своето бродче. Се почувствува засрамено, но сепак знаеше колку труд вложил во него. Двете момчиња ги спуштија своите бродчиња во водата. Пластичната едрилица на Бојан веднаш се оддалечи со голема брзина, додека „Езерската ѕвезда“ на Тео полека и достоинствено се лизгаше по брановите, водена само од силата на ветрот.",
        "[ 🎨 NanoBanana Prompt: Two boys at a lake pier. One boy is holding a beautiful, small wooden sailboat with a white sail, looking a bit shy. The other boy is laughing and holding a large, shiny plastic remote-controlled boat. In the style of a clean children's picture book, pastel colors, white background bleed --ar 16:9 ]",
        "Одеднаш, времето се промени. Се крена силен, неочекуван летен ветер. Водата се разбранува. Едрилицата на Бојан излезе од контрола и силниот ветер ја однесе право во најгустиот дел од острите трски. Бојан очајно стискаше на далечинскиот управувач, но моторот на пластичното бродче се заглави во тревите, а острите трски почнаа да ја гребат тенката пластика.",
        "„Мојот брод! Ќе потоне!“ – извика Бојан со солзи во очите. Плитакот таму беше премногу длабок и каллив за децата да влезат, а ниту едно друго бродче на далечинско не можеше да се пробие низ густата трска без да се заглави.\nТео не размислуваше ниту секунда. Тој го зеде долгото јаже што дедо му го врза за „Езерската ѕвезда“ и внимателно ја насочи својата дрвена едрилица кон трските. Бидејќи „Езерската ѕвезда“ немаше мотор што би се заплеткал во тревите и беше направена од цврсто дрво, таа лесно се пробиваше низ острите стебленца. Ветерот го полнеше нејзиното бело едро и ја водеше точно до заглавеното бродче на Бојан.",
        "[ 🎨 NanoBanana Prompt: A brave little wooden toy sailboat gracefully sailing through sharp, thick reeds on a windy, wavy lake, pushing and rescuing a stuck plastic remote-controlled boat. In the style of a clean children's picture book, pastel colors, white background bleed --ar 16:9 ]",
        "Со вешт потег, Тео ја насочи „Езерската ѕвезда“ така што нејзиниот цврст дрвен труп нежно го истурка пластичното бродче надвор од густата мрежа од трски, сè додека Бојан не успеа да го дофати со рацете.",
        "Бојан ја прегрна својата изгребана пластична едрилица, а потоа го погледна Тео. Лицето му беше црвено од срам.\n„Ти благодарам, Тео,“ – рече тој тивко. „Твоето бродче можеби е старо, но е најхраброто и најцврстото бродче на езерото. Извини што ти се смеев.“\nТој ден Тео не победи на некаква трка, ниту пак имаше најбрзо бродче. Но, додека чекореше кон дома држејќи ја својата „Езерска ѕвезда“, со дедо Никола покрај него, тој се чувствуваше како најголемиот победник на светот."
    ]

    for p in paragraphs:
        if "NanoBanana" in p:
            para = doc.add_paragraph(p)
            para.alignment = WD_ALIGN_PARAGRAPH.CENTER
            para.runs[0].italic = True
            para.runs[0].font.size = Pt(11)
        else:
            doc.add_paragraph(p).alignment = WD_ALIGN_PARAGRAPH.JUSTIFY

    doc.add_page_break()
    doc.add_heading('ПРАШАЊА ЗА ТЕКСТОТ', 1)

    mcq = {
        "1": ("Каде Тео ја пронајде скршената макета на едрилицата?", ["А) Во дворот на дедо Никола.", "Б) На главното пристаниште.", "В) Во густата трска во плитакот.", "Г) Во една стара рибарска мрежа."]),
        "4": ("Од што дедо Никола го сошил новото бело едро за бродчето?", ["А) Од парче тенка хартија.", "Б) Од една стара рибарска мрежа.", "В) Од пластика.", "Г) Од едно старо платно."]),
        "5": ("Зошто Бојан му се смеел на Тео кога ги донеле бродчињата на пристаништето?", ["А) Затоа што Тео не знаел да плива.", "Б) Затоа што бродчето на Тео изгледало како парче старо дрво најдено во ѓубре.", "В) Затоа што бродчето на Тео веднаш потонало во водата.", "Г) Затоа што Тео немал далечински управувач."]),
        "6": ("Што се случило кога неочекувано се кренал силен летен ветер?", ["А) Бродчето на Тео потонало.", "Б) Дедо Никола дошол да ги прибере децата.", "В) Бродчето на Бојан излегло од контрола и се заглавило во трските.", "Г) Двете бродчиња се судриле и се скршиле."]),
        "8": ("Зошто Бојан не можел самиот да си го извади заглавеното бродче од трските?", ["А) Затоа што му се расипал далечинскиот управувач.", "Б) Затоа што се плашел од водата.", "В) Затоа што плитакот таму бил премногу длабок и каллив за да се влезе во него.", "Г) Затоа што Тео не му дозволувал да влезе во водата."]),
        "12": ("Која е главната порака (поука) на овој расказ?", ["А) Пластичните играчки се секогаш подобри од дрвените.", "Б) Трските во езерото се многу опасни за децата.", "В) Убавината и вредноста не се секогаш во тоа нештото да биде ново и скапо, току во вложениот труд и храброста.", "Г) За да победиш на трка, секогаш ти треба брод со мотор."]),
        "14": ("На крајот од приказната, Тео не победи на некаква трка, но се чувствуваше како „најголемиот победник на светот“. Зошто авторот ја завршува приказната на овој начин?", ["А) За да покаже дека Тео му го украл бродчето на Бојан.", "Б) За да објасни дека Тео тајно организирал друга трка и победил.", "В) За да покаже дека вистинската победа е тоа што со својот труд успеал да спаси пријател во неволја.", "Г) За да ни каже дека дедо Никола му купил златен пехар."])
    }

    open_q = {
        "2": ("Што му било потребно на Тео за да го поправи бродчето според зборовите на дедо му? Наведи две работи (материјали) од текстот.", 1, 2),
        "3": ("Најди го делот во текстот кога Тео за првпат ја извлекува макетата од водата. Како се чувствувал тој во тој момент? Објасни зошто се чувствувал така.", 2, 3),
        "9": ("Зошто „Езерската ѕвезда“ на Тео можела лесно да се пробие низ острите трски и да стигне до бродчето на Бојан, за разлика од другите бродчиња? Наведи една причина од текстот.", 1, 2),
        "10": ("Каква личност е Тео? Наведи една негова особина и дади пример од текстот што го покажува тоа.", 2, 3),
        "13": ("Авторот го насловил расказот „Спасувањето на Езерската ѕвезда“. Дали мислиш дека ова е соодветен наслов за приказната? Искористи информации од текстот за да го објасниш твојот одговор.", 2, 3)
    }

    for i in range(1, 15):
        num = str(i)
        if num in mcq:
            q, opts = mcq[num]
            doc.add_paragraph(f"{num}. {q}").runs[0].bold = True
            for o in opts:
                doc.add_paragraph(f"O  {o}").paragraph_format.left_indent = Inches(0.5)
        elif num in open_q:
            q, pts, lines = open_q[num]
            p = doc.add_paragraph()
            p.add_run(f"{num}. {q}").bold = True
            p.add_run(f" [✎ {pts} поен/и]").italic = True
            for _ in range(lines):
                doc.add_paragraph("_" * 60)
        elif num == "7":
            doc.add_paragraph("7. Спореди ги бродчињата на Тео и на Бојан. Во што се разликувале тие? Наведи две разлики врз основа на текстот. [✎ 2 поени]").runs[0].bold = True
            doc.add_paragraph("Разлика 1: " + "_"*60)
            doc.add_paragraph("Разлика 2: " + "_"*60)
        elif num == "11":
            doc.add_paragraph("11. Како се промениле чувствата на Бојан кон бродчето на Тео од почетокот до крајот на приказната? [✎ 2 поени]").runs[0].bold = True
            doc.add_paragraph("На почетокот Бојан чувствувал __________________________________________,")
            doc.add_paragraph("затоа што ________________________________________________________________.")
            doc.add_paragraph("На крајот Бојан чувствувал _________________________________________________,")
            doc.add_paragraph("затоа што ________________________________________________________________.")

    doc.add_paragraph("\n🛑 СТОП. КРАЈ НА ТЕСТОТ.")
    doc.save("PIRLS_LakeStar_Ucenik.docx")
    print("Student test generated!")

create_lake_star_student()
